#include <stdio.h>
int main(){
    int n,k;
    if(scanf("%d %d",&n,&k)!=2) return 0;
    int found=0;
    for(int i=0;i<n;i++){
        int x; scanf("%d",&x);
        if(x==k) found=1;
    }
    printf(found?"Yes\n":"No\n");
    return 0;
}

