import sys
def solve():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    n=int(next(it)); k=int(next(it))
    found=False
    for _ in range(n):
        if int(next(it))==k:
            found=True
    sys.stdout.write('Yes' if found else 'No')
if __name__=='__main__':
    solve()

